'use client'

import { AnimatedBackground } from '../components/animated-background'
import { NavHeader } from '../components/nav-header'
import { HeroSection } from '../components/hero-section'
import { AuthCard } from '../components/auth-card'
import { Footer } from '../components/footer'

export default function Home() {
  return (
    <main className="relative w-full min-h-screen flex flex-col overflow-hidden bg-gradient-to-br from-background via-white/5 to-background">
      <AnimatedBackground />

      {/* Navigation */}
      <NavHeader />

      {/* Main Content */}
      <div className="relative z-10 flex-1 flex flex-col lg:flex-row gap-8 lg:gap-12 items-stretch w-full">
        {/* Left side - Hero */}
        <HeroSection />

        {/* Right side - Auth Card */}
        <div className="flex items-center justify-center px-6 lg:px-12 py-12 lg:py-0 flex-1 w-full">
          <AuthCard />
        </div>
      </div>

      {/* Footer */}
      <Footer />
    </main>
  )
}
